INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (1, 2, "", "---", 1, 1, "", "アヤネ", 0, 1);
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (3, 1, "", "---", 1, 2, "逆境に屈することなく、部員たちを引っ張る主将。ミート力を活かした安定感のある打撃が持ち味。", "アサヒ", 6000, 0);
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (0, 3, "ホームランを連発すると、連発数に応じてパワーアップする", "アドレナリン", 1, 3, "無愛想だが仲間を大切に想う気持ちは誰よりも強い男。ケンカで鍛えた腕っぷしが自慢のパワーヒッター。", "部員3", 16000, 3);
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (2, 2, "幸運のハプニングを呼び込む", "ラッキー", 1, 4, "みんなからの厚い信頼を集める期待の助っ人部員。実力は未知数だが幸運なハプニングを呼び込む。", "{0}", 30000, 2);
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (1, 0, "", "", 0, 5, "みんなの知らない極秘情報がのっているおまけページ。決して誰かに見せてはいけない。", "選手名鑑 おまけページ", 50000, 1);
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (1, 1, "", "", 0, 6, "", "選手名鑑 おまけページ", 50000, 0);
